external_knowledge:
- 'films' refers to movies;
- 'American renters' refers to customers in the USA;
- 'zip codes whisper the tale of a specific region' refers to postal codes starting with '1';
- 'the decade of digital dominance' refers to the years between 2010 and 2022;
- 'whose return is more than a mere fifty' refers to the condition that more than 50 films were rented in a given year.

sql:
SELECT AVG(rental_rate) AS average_rental_rate
FROM films
WHERE certificate = 'PG-13';

SELECT SUM(f.rental_rate) AS total_revenue
FROM rentals r
JOIN films f ON r.film_id = f.film_id;

